#include <stdio.h>
#include <limits.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B;
        scanf("%d %d", &A, &B);
        int logB = __builtin_ctz(B); // because B is power of two
        int best = INT_MAX;
        int v = A;
        for (int k = 0; v > 0; ++k) {
            if (v <= B && (v & (v - 1)) == 0) { // v is power of two and not larger than B
                int logV = __builtin_ctz(v);
                int steps = k + (logB - logV);
                if (steps < best) best = steps;
            }
            v >>= 1; // one more division (floor)
        }
        printf("%d\n", best);
    }
    return 0;
}

