const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
function isPowerOfTwo(x) {
  return x > 0 && (x & (x - 1)) === 0;
}
for (let t = 0; t < T; ++t) {
  let A = Number(input[idx++]);
  let B = Number(input[idx++]);
  const logB = Math.floor(Math.log2(B)); // B is power of two
  let best = Number.MAX_SAFE_INTEGER;
  let v = A;
  let k = 0;
  while (v > 0) {
    if (v <= B && isPowerOfTwo(v)) {
      const logV = Math.floor(Math.log2(v));
      const steps = k + (logB - logV);
      if (steps < best) best = steps;
    }
    v = v >> 1; // floor division by 2
    k++;
  }
  output.push(String(best));
}
console.log(output.join('\n'));

